package com.project.orcamentofly.command;

/**
 * Command Pattern - Interface que define o contrato para todos os comandos
 * Responsável por encapsular requisições como objetos
 */
public interface Command {
    void executar();
    void desfazer();
}

package com.project.orcamentofly.command;

import java.util.Stack;

/**
 * Invocador do Command Pattern
 * Responsável por executar comandos e manter histórico de desfazer
 */
public class CommandInvoker {
    private final Stack<Command> historico;

    public CommandInvoker() {
        this.historico = new Stack<>();
    }

    /**
     * Executa um comando e armazena no histórico
     */
    public void executar(Command comando) {
        if (comando != null) {
            comando.executar();
            historico.push(comando);
        }
    }

    /**
     * Desfaz o último comando executado
     */
    public void desfazer() {
        if (!historico.isEmpty()) {
            Command comando = historico.pop();
            comando.desfazer();
        }
    }

    /**
     * Desfaz os últimos N comandos
     */
    @SuppressWarnings("unused")
    public void desfazerN(int quantidade) {
        for (int i = 0; i < quantidade && !historico.isEmpty(); i++) {
            desfazer();
        }
    }

    /**
     * Limpa o histórico
     */
    @SuppressWarnings("unused")
    public void limparHistorico() {
        historico.clear();
    }

    /**
     * Retorna o tamanho do histórico
     */
    @SuppressWarnings("unused")
    public int getTamanhoHistorico() {
        return historico.size();
    }
}

package com.project.orcamentofly.command.cliente;

import com.project.orcamentofly.command.Command;
import com.project.orcamentofly.model.Cliente;
import com.project.orcamentofly.service.ClienteService;

/**
 * Comando concreto para atualizar um cliente
 */
public class AtualizarClienteCommand implements Command {
    private final ClienteService service;
    private final Cliente cliente;
    private final Cliente clienteAnterior;

    public AtualizarClienteCommand(ClienteService service, Cliente cliente, Cliente clienteAnterior) {
        this.service = service;
        this.cliente = cliente;
        this.clienteAnterior = clienteAnterior;
    }

    @Override
    public void executar() {
        service.atualizar(cliente);
    }

    @Override
    public void desfazer() {
        // Restaurar o estado anterior do cliente
        if (clienteAnterior != null) {
            service.atualizar(clienteAnterior);
        }
    }
}

package com.project.orcamentofly.command.cliente;

import com.project.orcamentofly.command.Command;
import com.project.orcamentofly.model.Cliente;
import com.project.orcamentofly.service.ClienteService;

/**
 * Comando concreto para inserir um cliente
 */
public class InserirClienteCommand implements Command {
    private final ClienteService service;
    private final Cliente cliente;

    public InserirClienteCommand(ClienteService service, Cliente cliente) {
        this.service = service;
        this.cliente = cliente;
    }

    @Override
    public void executar() {
        service.inserir(cliente);
    }

    @Override
    public void desfazer() {
        // Implementar lógica de desfazer (deletar o cliente inserido)
        if (cliente.getId() > 0) {
            service.deletar(cliente.getId());
        }
    }
}

package com.project.orcamentofly.command.produto;

import com.project.orcamentofly.command.Command;
import com.project.orcamentofly.model.Produto;
import com.project.orcamentofly.model.factory.ProdutoFactory;
import com.project.orcamentofly.service.ProdutoService;

/**
 * Comando concreto para inserir um produto usando Factory Pattern
 */
public class InserirProdutoCommand implements Command {
    private final ProdutoService service;
    private final String nome;
    private final String descricao;
    private final double valorUnitario;
    private final int estoque;
    private Produto produtoInserido;

    public InserirProdutoCommand(ProdutoService service, String nome, String descricao, double valorUnitario, int estoque) {
        this.service = service;
        this.nome = nome;
        this.descricao = descricao;
        this.valorUnitario = valorUnitario;
        this.estoque = estoque;
    }

    @Override
    public void executar() {
        // Usar Factory Pattern para criar o produto
        Produto produto = ProdutoFactory.criarProduto(nome, descricao, valorUnitario, estoque);
        service.inserir(produto);
        this.produtoInserido = produto;
    }

    @Override
    public void desfazer() {
        // Implementar lógica de desfazer
        if (produtoInserido != null && produtoInserido.getId() > 0) {
            service.deletar(produtoInserido);
        }
    }
}

package com.project.orcamentofly.controller;

import com.project.orcamentofly.model.Cliente;
import com.project.orcamentofly.service.ClienteService;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/clientes")
public class ClienteController {

    private final ClienteService service = new ClienteService();

    @GetMapping("/consultarTodos")
    public ResponseEntity<List<Cliente>> consultarTodos() {
        try {
            return ResponseEntity.ok().body(service.consultarTodos());
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @GetMapping("/consultarById/{id}")
    public ResponseEntity<Cliente> consultarById(@PathVariable int id) {
        try {
            return ResponseEntity.ok().body(service.consultarById(id));
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @PostMapping("/inserir")
    public ResponseEntity<Void> inserir(@RequestBody Cliente cliente) {
        try {
            service.inserir(cliente);
            return ResponseEntity.status(HttpStatus.CREATED).build();
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @PutMapping("/atualizar")
    public ResponseEntity<Void> atualizar(@RequestBody Cliente cliente) {
        try {
            service.atualizar(cliente);
            return ResponseEntity.ok().build();
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @DeleteMapping("/deletar/{id}")
    public ResponseEntity<Void> deletar(@PathVariable int id) {
        try {
            service.deletar(id);
            return ResponseEntity.noContent().build();
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}

package com.project.orcamentofly.controller;

import com.project.orcamentofly.command.CommandInvoker;
import com.project.orcamentofly.command.cliente.AtualizarClienteCommand;
import com.project.orcamentofly.command.cliente.InserirClienteCommand;
import com.project.orcamentofly.exception.BadRequestException;
import com.project.orcamentofly.exception.ResourceNotFoundException;
import com.project.orcamentofly.model.Cliente;
import com.project.orcamentofly.service.ClienteService;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/clientes")
public class ClienteController {

    private final ClienteService service = new ClienteService();
    private final CommandInvoker invoker = new CommandInvoker();

    @GetMapping("/consultarTodos")
    public ResponseEntity<List<Cliente>> consultarTodos() {
        try {
            List<Cliente> clientes = service.consultarTodos();
            if (clientes == null || clientes.isEmpty()) {
                throw new ResourceNotFoundException("Nenhum cliente encontrado");
            }
            return ResponseEntity.ok().body(clientes);
        } catch (ResourceNotFoundException e) {
            throw e;
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @GetMapping("/consultarById/{id}")
    public ResponseEntity<Cliente> consultarById(@PathVariable int id) {
        try {
            if (id <= 0) {
                throw new BadRequestException("ID do cliente inválido");
            }
            Cliente cliente = service.consultarById(id);
            if (cliente == null) {
                throw new ResourceNotFoundException("Cliente com ID " + id + " não encontrado");
            }
            return ResponseEntity.ok().body(cliente);
        } catch (BadRequestException | ResourceNotFoundException e) {
            throw e;
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @PostMapping("/inserir")
    public ResponseEntity<Void> inserir(@RequestBody Cliente cliente) {
        try {
            if (cliente == null || cliente.getNome() == null || cliente.getNome().isEmpty()) {
                throw new BadRequestException("Nome do cliente é obrigatório");
            }
            if (cliente.getEmail() == null || cliente.getEmail().isEmpty()) {
                throw new BadRequestException("Email do cliente é obrigatório");
            }
            if (cliente.getCpf() == null || cliente.getCpf().isEmpty()) {
                throw new BadRequestException("CPF do cliente é obrigatório");
            }
            // Usando Command Pattern para executar a inserção
            InserirClienteCommand comando = new InserirClienteCommand(service, cliente);
            invoker.executar(comando);
            return ResponseEntity.status(HttpStatus.CREATED).build();
        } catch (BadRequestException e) {
            throw e;
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @PutMapping("/atualizar")
    public ResponseEntity<Void> atualizar(@RequestBody Cliente cliente) {
        try {
            if (cliente == null || cliente.getId() <= 0) {
                throw new BadRequestException("ID do cliente inválido");
            }
            if (cliente.getNome() == null || cliente.getNome().isEmpty()) {
                throw new BadRequestException("Nome do cliente é obrigatório");
            }
            Cliente existente = service.consultarById(cliente.getId());
            if (existente == null) {
                throw new ResourceNotFoundException("Cliente com ID " + cliente.getId() + " não encontrado");
            }
            // Usando Command Pattern para executar a atualização
            AtualizarClienteCommand comando = new AtualizarClienteCommand(service, cliente, existente);
            invoker.executar(comando);
            return ResponseEntity.ok().build();
        } catch (BadRequestException | ResourceNotFoundException e) {
            throw e;
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @DeleteMapping("/deletar/{id}")
    public ResponseEntity<Void> deletar(@PathVariable int id) {
        try {
            if (id <= 0) {
                throw new BadRequestException("ID do cliente inválido");
            }
            Cliente existente = service.consultarById(id);
            if (existente == null) {
                throw new ResourceNotFoundException("Cliente com ID " + id + " não encontrado");
            }
            service.deletar(id);
            return ResponseEntity.noContent().build();
        } catch (BadRequestException | ResourceNotFoundException e) {
            throw e;
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}

