package com.project.orcamentofly.exception;

public class BadRequestException extends RuntimeException {
    public BadRequestException(String message) {
        super(message);
    }
}

package com.project.orcamentofly.exception;

import java.time.LocalDateTime;

public class ErrorResponse {
    private int status;
    private String message;
    private LocalDateTime timestamp;

    public ErrorResponse(int status, String message) {
        this.status = status;
        this.message = message;
        this.timestamp = LocalDateTime.now();
    }

    public int getStatus() {
        return status;
    }

    public void setStatus(int status) {
        this.status = status;
    }

    public String getMessage() {
        return message;
    }

    public void setMessage(String message) {
        this.message = message;
    }

    public LocalDateTime getTimestamp() {
        return timestamp;
    }

    public void setTimestamp(LocalDateTime timestamp) {
        this.timestamp = timestamp;
    }
}

package com.project.orcamentofly.exception;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.ControllerAdvice;
import org.springframework.web.bind.annotation.ExceptionHandler;

@ControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(BadRequestException.class)
    public ResponseEntity<ErrorResponse> handleBadRequestException(BadRequestException ex) {
        ErrorResponse errorResponse = new ErrorResponse(400, ex.getMessage());
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(errorResponse);
    }

    @ExceptionHandler(ResourceNotFoundException.class)
    public ResponseEntity<ErrorResponse> handleResourceNotFoundException(ResourceNotFoundException ex) {
        ErrorResponse errorResponse = new ErrorResponse(404, ex.getMessage());
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(errorResponse);
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ErrorResponse> handleGeneralException(Exception ex) {
        ErrorResponse errorResponse = new ErrorResponse(500, "Erro interno no servidor: " + ex.getMessage());
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(errorResponse);
    }
}

package com.project.orcamentofly.exception;

public class ResourceNotFoundException extends RuntimeException {
    public ResourceNotFoundException(String message) {
        super(message);
    }
}

package com.project.orcamentofly.model.factory;

import com.project.orcamentofly.model.Cliente;
import com.project.orcamentofly.model.Orcamento;
import com.project.orcamentofly.model.enums.StatusOrcamento;
import java.time.LocalDate;

/**
 * Factory Pattern - Fábrica para criar instâncias de Orçamento
 * Responsável pela criação centralizada de objetos Orçamento
 */
public class OrcamentoFactory {

    public static Orcamento criarOrcamento(Cliente cliente, LocalDate dataOrcamento, String observacao, double valorTotal) {
        if (cliente == null) {
            throw new IllegalArgumentException("Cliente não pode ser nulo");
        }
        if (dataOrcamento == null) {
            throw new IllegalArgumentException("Data do orçamento não pode ser nula");
        }
        if (valorTotal <= 0) {
            throw new IllegalArgumentException("Valor total deve ser maior que zero");
        }
        return new Orcamento(cliente, dataOrcamento, observacao, valorTotal);
    }

    public static Orcamento criarOrcamento(int id, Cliente cliente, LocalDate dataOrcamento, String observacao, double valorTotal, StatusOrcamento status) {
        if (id <= 0) {
            throw new IllegalArgumentException("ID do orçamento deve ser maior que zero");
        }
        Orcamento orcamento = criarOrcamento(cliente, dataOrcamento, observacao, valorTotal);
        orcamento.setId(id);
        orcamento.setStatus(status);
        return orcamento;
    }

    public static Orcamento criarOrcamentoPendente(Cliente cliente, LocalDate dataOrcamento, String observacao, double valorTotal) {
        Orcamento orcamento = criarOrcamento(cliente, dataOrcamento, observacao, valorTotal);
        orcamento.setStatus(StatusOrcamento.PENDENTE);
        return orcamento;
    }
}

package com.project.orcamentofly.model.factory;

import com.project.orcamentofly.model.Produto;

/**
 * Factory Pattern - Fábrica para criar instâncias de Produto
 * Responsável pela criação centralizada de objetos Produto
 */
public class ProdutoFactory {

    public static Produto criarProduto(String nome, String descricao, double valorUnitario, int estoque) {
        if (nome == null || nome.isEmpty()) {
            throw new IllegalArgumentException("Nome do produto não pode ser vazio");
        }
        if (valorUnitario <= 0) {
            throw new IllegalArgumentException("Valor unitário deve ser maior que zero");
        }
        if (estoque < 0) {
            throw new IllegalArgumentException("Estoque não pode ser negativo");
        }
        return new Produto(nome, descricao, valorUnitario, estoque);
    }

    @SuppressWarnings("unused")
    public static Produto criarProduto(int id, String nome, String descricao, double valorUnitario, int estoque) {
        if (id <= 0) {
            throw new IllegalArgumentException("ID do produto deve ser maior que zero");
        }
        Produto produto = criarProduto(nome, descricao, valorUnitario, estoque);
        produto.setId(id);
        return produto;
    }
}

package com.project.orcamentofly.model.factory;

import com.project.orcamentofly.model.Servico;

/**
 * Factory Pattern - Fábrica para criar instâncias de Serviço
 * Responsável pela criação centralizada de objetos Serviço
 */
public class ServicoFactory {

    public static Servico criarServico(String nome, String descricao, double valorUnitario) {
        if (nome == null || nome.isEmpty()) {
            throw new IllegalArgumentException("Nome do serviço não pode ser vazio");
        }
        if (valorUnitario <= 0) {
            throw new IllegalArgumentException("Valor unitário deve ser maior que zero");
        }
        return new Servico(nome, descricao, valorUnitario);
    }

    public static Servico criarServico(int id, String nome, String descricao, double valorUnitario) {
        if (id <= 0) {
            throw new IllegalArgumentException("ID do serviço deve ser maior que zero");
        }
        Servico servico = criarServico(nome, descricao, valorUnitario);
        servico.setId(id);
        return servico;
    }
}
